## call_with_meta Implementation

```rust
pub async fn call_with_meta(&self, input: S::Input) -> Result<CallResult<S>, PredictError> {
    // 1. Get adapter and LM from global settings
    let (adapter, lm) = {
        let guard = GLOBAL_SETTINGS.read().unwrap();
        let settings = guard.as_ref().unwrap();
        (settings.adapter.clone(), Arc::clone(&settings.lm))
    };

    // 2. Build messages using typed ChatAdapter methods
    let system = ChatAdapter.format_system_message_typed::<S>()?;
    let user = ChatAdapter.format_user_message_typed::<S>(&input);
    let demos = self.format_demos_typed::<S>();

    let mut chat = Chat::new(vec![]);
    chat.push("system", &system);
    chat.push_all(&demos);
    chat.push("user", &user);

    // 3. Call LM
    let response = lm.call(chat, self.tools.clone()).await
        .map_err(|e| PredictError::Lm { source: e.into() })?;

    // 4. Extract metadata
    let raw_response = response.output.content().to_string();
    let lm_usage = response.usage.clone();

    // 5. Parse response using jsonish
    let (typed_output, field_metas) = ChatAdapter.parse_response_typed::<S>(&response.output)
        .map_err(|e| PredictError::Parse { source: e, raw_response: raw_response.clone(), lm_usage: lm_usage.clone() })?;

    // 6. Construct final output
    let output = S::from_parts(input, typed_output);

    // 7. Record trace (if enabled)
    let node_id = if crate::trace::is_tracing() {
        crate::trace::record_node(
            crate::trace::NodeType::Predict {
                signature_name: std::any::type_name::<S>().to_string(),
                // NOTE: No longer stores Arc<dyn MetaSignature>
            },
            vec![],
            None,
        )
    } else {
        None
    };

    // 8. Return CallResult with all metadata
    Ok(CallResult {
        output,
        raw_response,
        lm_usage,
        tool_calls: response.tool_calls,
        tool_executions: vec![],
        node_id,
        fields: field_metas,
    })
}
```

## IMPORTANT: Tracing Integration

The existing trace system stores `Arc<dyn MetaSignature>` in NodeType::Predict. For typed version:

1. **Option A**: Remove signature from NodeType, just store name
   ```rust
   NodeType::Predict { signature_name: String }
   ```

2. **Option B**: Keep for compatibility, implement MetaSignature for S
   ```rust
   NodeType::Predict { signature_name: String, signature: Option<Arc<dyn MetaSignature>> }
   ```

**Recommended**: Option A (cleaner), update trace files in same PR.

## Files to Also Modify
- `crates/dspy-rs/src/trace/dag.rs` - Update NodeType enum
- `crates/dspy-rs/src/trace/context.rs` - Update any MetaSignature references

## Testing Strategy

```rust
#[tokio::test]
async fn test_predict_call_typed() {
    let predict = Predict::<QA>::new();
    let result = predict.call(QAInput { question: "Test?".into(), context: None }).await;
    assert!(result.is_ok());
}

#[tokio::test]
async fn test_predict_call_with_meta() {
    let predict = Predict::<QA>::new();
    let result = predict.call_with_meta(QAInput { ... }).await?;
    assert!(!result.raw_response.is_empty());
    assert!(result.lm_usage.prompt_tokens > 0);
}

#[tokio::test]
async fn test_predict_tracing_integration() {
    crate::trace::start();
    let predict = Predict::<QA>::new();
    let result = predict.call_with_meta(...).await?;
    assert!(result.node_id.is_some());
    crate::trace::stop();
}
```

## Acceptance Criteria
1. call() returns typed S output
2. call_with_meta() returns CallResult<S> with all metadata
3. Tracing records node without requiring MetaSignature trait object
4. Error mapping into PredictError variants works correctly
